mapper.select:
select orders.*, goods.name as goodsName, goods.img as goodsImg, user.name as userName from orders left join goods on orders.goods_id = goods.id left join user on orders.user_id = user.id
and orders.order_no like concat('%', #{orderNo}, '%') and orders.user_id = #{userId}
order by orders.id desc

mapper.update:
update orders set order_no = #{orderNo}, goods_id = #{goodsId}, num = #{num},
user_id = #{userId}, status = #{status}, time = #{time}
where id = #{id}
